class LFUCache {
    private int capacity;
    private Map<Integer, Integer> valueMap;
    private Map<Integer, Integer> countMap;
    private Map<Integer, LinkedHashSet<Integer>> countToKeyMap;
    private int minCount;

    public LFUCache(int capacity) {
        this.capacity = capacity;
        this.valueMap = new HashMap<>();
        this.countMap = new HashMap<>();
        this.countToKeyMap = new HashMap<>();
        this.minCount = 0;
    }

    public int get(int key) {
        if (!valueMap.containsKey(key)) {
            return -1;
        }
        int count = countMap.get(key);
        countMap.put(key, count + 1);
        countToKeyMap.get(count).remove(key);
        if (countToKeyMap.get(count).size() == 0) {
            countToKeyMap.remove(count);
            if (count == minCount) {
                minCount++;
            }
        }
        countToKeyMap.computeIfAbsent(count + 1, z -> new LinkedHashSet<>()).add(key);
        return valueMap.get(key);
    }

    public void put(int key, int value) {
        if (capacity <= 0) {
            return;
        }
        if (valueMap.containsKey(key)) {
            valueMap.put(key, value);
            get(key);
            return;
        }
        if (valueMap.size() >= capacity) {
            int evict = countToKeyMap.get(minCount).iterator().next();
            countToKeyMap.get(minCount).remove(evict);
            if (countToKeyMap.get(minCount).size() == 0) {
                countToKeyMap.remove(minCount);
            }
            valueMap.remove(evict);
            countMap.remove(evict);
        }
        valueMap.put(key, value);
        countMap.put(key, 1);
        minCount = 1;
        countToKeyMap.computeIfAbsent(1, z -> new LinkedHashSet<>()).add(key);
    }
}
